class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        from math import gcd
        from collections import defaultdict

        def find(parent, x):
            if parent[x] != x:
                parent[x] = find(parent, parent[x])
            return parent[x]

        def union(parent, rank, x, y):
            root_x = find(parent, x)
            root_y = find(parent, y)
            if root_x == root_y:
                return
            if rank[root_x] > rank[root_y]:
                parent[root_y] = root_x
            else:
                parent[root_x] = root_y
                if rank[root_x] == rank[root_y]:
                    rank[root_y] += 1

        # Edge case: if nums has only one element, it's trivially connected
        if len(nums) == 1:
            return True

        # Find all prime factors for each number
        max_num = max(nums)
        prime_factors = defaultdict(set)
        for i, num in enumerate(nums):
            temp = num
            for p in range(2, int(temp**0.5) + 1):
                while temp % p == 0:
                    prime_factors[p].add(i)
                    temp //= p
            if temp > 1:
                prime_factors[temp].add(i)

        # Union-Find setup
        parent = {}
        rank = {}
        for i in range(len(nums)):
            parent[i] = i
            rank[i] = 1

        # Union indices by their prime factors
        for primes in prime_factors.values():
            indices = list(primes)
            if len(indices) < 2:
                continue
            first = indices[0]
            for idx in indices[1:]:
                union(parent, rank, first, idx)

        # Check if all indices are in the same set
        root = find(parent, 0)
        for i in range(1, len(nums)):
            if find(parent, i) != root:
                return False
        return True
